mapper.select:
SELECT p.* FROM post p WHERE p.poststatus != 2 AND ( p.visible = 0 OR (p.visible = 1 AND p.posterid = #{userMeId}) OR (p.visible = 2 AND EXISTS ( SELECT 1 FROM relation r WHERE r.ourstatus = 2 AND ( (r.myid = p.posterid AND r.itsid = #{userMeId}) OR (r.myid = #{userMeId} AND r.itsid = p.posterid) ) )) ) AND p.posterid = #{posterId}
AND p.type = #{type}
AND p.poststatus = #{status}
AND p.itemname LIKE CONCAT('%', #{itemName}, '%')
AND p.itemplace LIKE CONCAT('%', #{itemPlace}, '%')
ORDER BY (IF(p.pinornot = 1 AND (p.top_expire_time IS NULL OR p.top_expire_time > NOW()), 1, 0)) DESC, p.posttime DESC
